+type AgentRunOutcome = { text: string; error?: string };
+
+const EMPTY_DELEGATE_OUTPUT = "Delegated agent completed without textual output.";
+
+function delegationInput(input: unknown): { agentId: string; instructions: string } | null {
+  if (!input || typeof input !== "object") return null;
+  const { agent_id, instructions } = input as Record<string, unknown>;
+  return typeof agent_id === "string" && typeof instructions === "string"
+    ? { agentId: agent_id, instructions }
+    : null;
+}
+
+function toolResultPayload(toolUseId: string, content: string, isError: boolean): string {
+  return JSON.stringify({
+    type: "tool_result",
+    is_error: isError,
+    content,
+    tool_use_id: toolUseId,
+  });
+}
+
+/**
+ * Runs one agent turn and, when that turn uses delegate_task, recursively runs
+ * the requested agent before re-invoking this agent with the corresponding
+ * tool_result.  Nested failures intentionally stay inside tool_result so the
+ * delegating agent can decide how to recover.
+ */
+async function* runAgentConversation(
+  agentId: string,
+  provider: NonNullable<ReturnType<typeof globalRegistry.getProviderForAgent>>,
+  agentConfig: NonNullable<ReturnType<typeof globalRegistry.getAgent>>,
+  request: ChatRequest,
+  initialMessage: string,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: string[],
+  suppressErrors: boolean,
+): AsyncGenerator<StreamResponse, AgentRunOutcome> {
+  let message = initialMessage;
+  let allText = "";
+  let generatedToolUseId = 0;
+
+  while (true) {
+    let delegated: { toolUseId: string; agentId: string; instructions: string } | undefined;
+
+    const providerRequest: ProviderChatRequest = {
+      message,
+      sessionId: request.sessionId,
+      requestId: request.requestId,
+      workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+    };
+
+    try {
+      for await (const response of provider.executeChat(providerRequest, {
+        debugMode,
+        abortController,
+        temperature: agentConfig.config?.temperature,
+        maxTokens: agentConfig.config?.maxTokens,
+      })) {
+        const chatRoomMessage = createChatRoomMessage(response, agentId);
+        if (chatRoomMessage) {
+          yield { type: "claude_json", data: { type: "chat_room_message", message: chatRoomMessage, session_id: request.sessionId } };
+        }
+
+        if (response.type === "text") {
+          const text = response.content || "";
+          allText += text;
+          yield { type: "claude_json", data: { type: "assistant", content: text, model: response.metadata?.model } };
+        } else if (response.type === "tool_use") {
+          const toolUseId = response.toolUseId || `${agentId}-delegate-${++generatedToolUseId}`;
+          // Preserve the provider tool event, including the ID required to pair it
+          // with the tool_result emitted below.
+          yield {
+            type: "claude_json",
+            data: {
+              type: "assistant",
+              message: { content: [{ type: "tool_use", id: toolUseId, name: response.toolName, input: response.toolInput }] },
+              session_id: request.sessionId,
+            },
+          };
+
+          if (response.toolName === "delegate_task") {
+            const input = delegationInput(response.toolInput);
+            if (!input) {
+              delegated = { toolUseId, agentId: "", instructions: "" };
+            } else if (!delegated) {
+              delegated = { toolUseId, ...input };
+            }
+          }
+        } else if (response.type === "error") {
+          const error = response.error || "Agent run failed";
+          return { text: allText, error };
+        }
+      }
+    } catch (error) {
+      return { text: allText, error: error instanceof Error ? error.message : String(error) };
+    }
+
+    if (!delegated) return { text: allText };
+
+    let resultContent: string;
+    let isError = false;
+    if (!delegated.agentId) {
+      resultContent = "delegate_task requires string agent_id and instructions.";
+      isError = true;
+    } else if (delegationPath.includes(delegated.agentId)) {
+      resultContent = `Circular delegation detected for agent '${delegated.agentId}'.`;
+      isError = true;
+      yield { type: "error", error: resultContent };
+    } else {
+      const subProvider = globalRegistry.getProviderForAgent(delegated.agentId);
+      const subAgent = globalRegistry.getAgent(delegated.agentId);
+      if (!subProvider || !subAgent) {
+        resultContent = `Agent '${delegated.agentId}' not found or provider not available`;
+        isError = true;
+        yield { type: "error", error: resultContent };
+      } else {
+        const subOutcome = yield* runAgentConversation(
+          delegated.agentId, subProvider, subAgent, request, delegated.instructions,
+          abortController, debugMode, [...delegationPath, delegated.agentId], true,
+        );
+        isError = !!subOutcome.error;
+        resultContent = subOutcome.error || subOutcome.text || EMPTY_DELEGATE_OUTPUT;
+      }
+    }
+
+    const feedback = toolResultPayload(delegated.toolUseId, resultContent!, isError);
+    yield {
+      type: "claude_json",
+      data: {
+        type: "user",
+        message: { content: [{ type: "tool_result", tool_use_id: delegated.toolUseId, is_error: isError, content: feedback }] },
+        session_id: request.sessionId,
+      },
+    };
+    // The exact JSON string is the next user turn for the delegating agent.
+    message = feedback;
+  }
+}
